// 会话列表时间格式化 · 当天显时:分 · 7 天内显星期 · 更早显日期
export function fmtConversationTime(iso) {
  if (!iso) return ''
  const d = new Date(iso)
  if (Number.isNaN(d.getTime())) return ''
  const now = new Date()
  const sameDay = d.toDateString() === now.toDateString()
  if (sameDay) return d.toTimeString().substring(0, 5)
  const diffDays = (now - d) / 86400000
  if (diffDays < 7) return ['周日', '周一', '周二', '周三', '周四', '周五', '周六'][d.getDay()]
  return d.toLocaleDateString('zh-CN').replace(/\//g, '-')
}
